1	<script>
2	  import { onMount } from "svelte";
3	  import { _, locale } from 'svelte-i18n';
4	  import { setupI18n } from './lib/i18n.js';
5	  import { handleImportFromUrl, importToken } from "./lib/token.js";
6	  import Lobby from "./pages/Lobby.svelte";
7	  import GameRoom from "./pages/GameRoom.svelte";
8	  import History from "./pages/History.svelte";
9	  import TokenManager from "./components/TokenManager.svelte";
10	
11	  setupI18n();
12	
13	  let page = $state("lobby");
14	  let sessionId = $state(null);
15	  let showTokenManager = $state(false);
16	  let pendingImportToken = $state(null);
17	
18	  function navigate(to, id = null) {
19	    sessionId = id;
20	    page = to;
21	    const url = to === "game" ? `/game/${id}` : to === "history" ? "/history" : "/";
22	    window.history.pushState({}, "", url);
23	  }
24	
25	  function setLocale(lang) {
26	    locale.set(lang);
27	    localStorage.setItem('ludus_locale', lang);
28	  }
29	
30	  onMount(() => {
31	    const incoming = handleImportFromUrl();
32	    if (incoming) pendingImportToken = incoming;
33	
34	    const path = window.location.pathname;
35	    const match = path.match(/^\/game\/([^/]+)/);
36	    if (match) {
37	      page = "game";
38	      sessionId = match[1];
39	    } else if (path === "/history") {
40	      page = "history";
41	    }
42	
43	    window.addEventListener("popstate", () => {
44	      const p = window.location.pathname;
45	      const m = p.match(/^\/game\/([^/]+)/);
46	      if (m) { page = "game"; sessionId = m[1]; }
47	      else if (p === "/history") { page = "history"; sessionId = null; }
48	      else { page = "lobby"; sessionId = null; }
49	    });
50	  });
51	</script>
52	
53	<!-- Token import confirmation banner -->
54	{#if pendingImportToken}
55	  <div class="fixed inset-x-0 top-0 z-50 bg-yellow-100 border-b border-yellow-300 p-4 flex items-center justify-between gap-4
56	              dark:bg-yellow-900/60 dark:border-yellow-700">
57	    <p class="text-sm text-yellow-900 dark:text-yellow-200">
58	      {$_('token_import.prompt', { values: { token: pendingImportToken.slice(0, 8) + '…' } })}
59	    </p>
60	    <div class="flex gap-2 shrink-0">
61	      <button
62	        class="px-3 py-1 bg-yellow-600 text-white rounded text-sm hover:bg-yellow-700"
63	        onclick={() => { importToken(pendingImportToken); }}
64	      >{$_('token_import.confirm')}</button>
65	      <button
66	        class="px-3 py-1 bg-white border border-yellow-400 rounded text-sm dark:bg-gray-800 dark:border-yellow-600 dark:text-gray-200"
67	        onclick={() => { pendingImportToken = null; }}
68	      >{$_('token_import.cancel')}</button>
69	    </div>
70	  </div>
71	{/if}
72	
73	<!-- Top bar -->
74	<header class="bg-indigo-700 text-white px-4 py-3 flex items-center justify-between dark:bg-indigo-900">
75	  <button class="text-xl font-bold tracking-wide" onclick={() => navigate("lobby")}>
76	    Ludus
77	  </button>
78	  <div class="flex items-center gap-3">
79	    <div class="flex gap-1 text-xs">
80	      <button
81	        class="px-2 py-0.5 rounded transition-colors {$locale === 'en' || $locale?.startsWith('en-') ? 'bg-white/20 font-semibold' : 'opacity-70 hover:opacity-100'}"
82	        onclick={() => setLocale('en')}
83	      >EN</button>
84	      <button
85	        class="px-2 py-0.5 rounded transition-colors {$locale === 'de' || $locale?.startsWith('de-') ? 'bg-white/20 font-semibold' : 'opacity-70 hover:opacity-100'}"
86	        onclick={() => setLocale('de')}
87	      >DE</button>
88	    </div>
89	    <button
90	      class="text-sm underline opacity-80 hover:opacity-100"
91	      onclick={() => { showTokenManager = true; }}
92	    >
93	      {$_('nav.my_token')}
94	    </button>
95	  </div>
96	</header>
97	
98	<!-- Page content -->
99	<main class="max-w-2xl mx-auto px-4 py-6">
100	  {#if page === "lobby"}
101	    <Lobby onJoinGame={(id) => navigate("game", id)} onHistory={() => navigate("history")} />
102	  {:else if page === "game"}
103	    {#key sessionId}
104	      <GameRoom {sessionId} onBack={() => navigate("lobby")} onJoinGame={(id) => navigate("game", id)} />
105	    {/key}
106	  {:else if page === "history"}
107	    <History onBack={() => navigate("lobby")} onJoinGame={(id) => navigate("game", id)} />
108	  {/if}
109	</main>
110	
111	{#if showTokenManager}
112	  <TokenManager onClose={() => { showTokenManager = false; }} />
113	{/if}
