1	<script>
2	  import { onMount, onDestroy } from "svelte";
3	  import { _ } from 'svelte-i18n';
4	  import { api } from "../lib/api.js";
5	  import { createGameSocket } from "../lib/ws.js";
6	  import { subscribeToPush, unsubscribeFromPush, isPushSupported } from "../lib/push.js";
7	  import { getSavedUsername, saveUsername } from "../lib/username.js";
8	  import TicTacToe from "../games/TicTacToe.svelte";
9	  import ConnectFour from "../games/ConnectFour.svelte";
10	  import Battleship from "../games/Battleship.svelte";
11	
12	  const GAME_COMPONENTS = {
13	    tictactoe: TicTacToe,
14	    connect_four: ConnectFour,
15	    battleship: Battleship,
16	  };
17	
18	  let { sessionId, onBack, onJoinGame } = $props();
19	
20	  let session = $state(null);
21	  let error = $state(null);
22	  let socket = null;
23	
24	  let joinUsername = $state(getSavedUsername());
25	  let joining = $state(false);
26	
27	  let isParticipant = $derived(session?.my_username !== null && session?.my_username !== undefined);
28	
29	  let inviteCopied = $state(false);
30	  let inviteUrl = $derived(session ? `${location.origin}/game/${session.uuid}` : "");
31	
32	  let pushSupported = isPushSupported();
33	  let pushPermission = $state(Notification.permission ?? "default");
34	
35	  async function togglePush() {
36	    if (pushPermission === "granted") {
37	      await unsubscribeFromPush();
38	      pushPermission = "default";
39	    } else {
40	      const result = await subscribeToPush();
41	      pushPermission = result === "granted" ? "granted" : Notification.permission;
42	    }
43	  }
44	
45	  onMount(async () => {
46	    try {
47	      session = await api.getSession(sessionId);
48	    } catch (e) {
49	      error = e.message;
50	      return;
51	    }
52	
53	    socket = createGameSocket(sessionId, {
54	      onState: (s) => { session = s; },
55	      onError: (msg) => { error = msg; },
56	      onCancelled: () => { onBack(); },
57	    });
58	  });
59	
60	  onDestroy(() => socket?.close());
61	
62	  function sendAction(action) {
63	    socket?.sendAction(action);
64	  }
65	
66	  async function joinGame() {
67	    if (!joinUsername.trim()) return;
68	    joining = true;
69	    try {
70	      const trimmed = joinUsername.trim();
71	      saveUsername(trimmed);
72	      session = await api.joinSession(sessionId, trimmed);
73	    } catch (e) {
74	      error = e.message;
75	    } finally {
76	      joining = false;
77	    }
78	  }
79	
80	  async function copyInvite() {
81	    await navigator.clipboard.writeText(inviteUrl);
82	    inviteCopied = true;
83	    setTimeout(() => { inviteCopied = false; }, 2000);
84	  }
85	
86	  let isOwner = $derived(session?.players[0]?.username === myUsername);
87	
88	  let cancelling = $state(false);
89	
90	  async function cancelGame() {
91	    cancelling = true;
92	    try {
93	      await api.cancelSession(sessionId);
94	      onBack();
95	    } catch (e) {
96	      error = e.message;
97	      cancelling = false;
98	    }
99	  }
100	
101	  let rematching = $state(false);
102	
103	  async function requestRematch() {
104	    rematching = true;
105	    try {
106	      const newSession = await api.rematch(sessionId);
107	      onJoinGame(newSession.uuid);
108	    } catch (e) {
109	      error = e.message;
110	    } finally {
111	      rematching = false;
112	    }
113	  }
114	
115	  function goToRematch() {
116	    onJoinGame(session.rematch_session_id);
117	  }
118	
119	  let GameComponent = $derived(session ? GAME_COMPONENTS[session.game_slug] : null);
120	  let myUsername = $derived(session?.my_username ?? null);
121	</script>
122	
123	<button class="text-sm text-indigo-600 dark:text-indigo-400 mb-4 hover:underline" onclick={onBack}>
124	  {$_('game_room.back')}
125	</button>
126	
127	{#if error}
128	  <p class="text-red-500 mb-4">{error}</p>
129	{/if}
130	
131	{#if !session}
132	  <p class="text-gray-500 dark:text-gray-400">{$_('game_room.loading')}</p>
133	{:else}
134	  <div class="flex items-center justify-between mb-4">
135	    <h1 class="text-xl font-bold">{$_(`games.${session.game_slug}.name`, { default: session.game_slug })}</h1>
136	    <div class="flex items-center gap-2">
137	      {#if pushSupported && isParticipant && session.status !== "finished"}
138	        <button
139	          class="text-xs px-2 py-1 rounded border transition-colors
140	                 {pushPermission === 'granted'
141	                   ? 'bg-indigo-50 border-indigo-300 text-indigo-700 dark:bg-indigo-900/30 dark:border-indigo-600 dark:text-indigo-300'
142	                   : 'bg-gray-50 border-gray-300 text-gray-500 hover:border-indigo-300 dark:bg-gray-800 dark:border-gray-600 dark:text-gray-400'}"
143	          onclick={togglePush}
144	          title={pushPermission === 'granted' ? $_('game_room.push_on_title') : $_('game_room.push_off_title')}
145	        >
146	          {pushPermission === "granted" ? $_('game_room.push_on') : $_('game_room.push_off')}
147	        </button>
148	      {/if}
149	      <span class="text-sm px-2 py-1 rounded bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300">
150	        {#if session.status === "waiting"}
151	          {$_('game_room.status_waiting')}
152	        {:else if session.status === "playing"}
153	          {$_('game_room.status_playing')}
154	        {:else if session.status === "finished"}
155	          {$_('game_room.status_finished')}
156	        {:else}
157	          {session.status}
158	        {/if}
159	      </span>
160	    </div>
161	  </div>
162	
163	  <!-- Players -->
164	  <div class="flex gap-3 mb-4 text-sm flex-wrap">
165	    {#each session.players as p}
166	      <span class="px-2 py-1 bg-indigo-100 rounded dark:bg-indigo-900/40 dark:text-indigo-200">
167	        {p.username}{p.username === myUsername ? ' ' + $_('game_card.you') : ""}
168	      </span>
169	    {/each}
170	  </div>
171	
172	  <!-- Waiting: invite link + optional join form -->
173	  {#if session.status === "waiting"}
174	    <div class="p-4 rounded-lg mb-4 space-y-3
175	                bg-yellow-50 border border-yellow-200
176	                dark:bg-yellow-900/20 dark:border-yellow-700">
177	      <p class="text-sm text-yellow-800 dark:text-yellow-300">{$_('game_room.waiting_title')}</p>
178	
179	      {#if isParticipant}
180	      <div>
181	        <p class="text-xs text-gray-500 dark:text-gray-400 mb-1">{$_('game_room.invite_link')}</p>
182	        <div class="flex gap-2">
183	          <input
184	            class="flex-1 border rounded px-2 py-1 text-sm font-mono bg-white
185	                   dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200"
186	            readonly
187	            value={inviteUrl}
188	          />
189	          <button
190	            class="px-3 py-1 bg-indigo-600 text-white rounded text-sm hover:bg-indigo-700"
191	            onclick={copyInvite}
192	          >
193	            {inviteCopied ? $_('game_room.copied') : $_('game_room.copy')}
194	          </button>
195	        </div>
196	      </div>
197	      {/if}
198	
199	      {#if !isParticipant}
200	        <div class="flex gap-2 pt-1 flex-wrap">
201	          <input
202	            class="border rounded px-3 py-1 text-sm
203	                   dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200 dark:placeholder-gray-500"
204	            placeholder={$_('game_room.join_placeholder')}
205	            bind:value={joinUsername}
206	          />
207	          <button
208	            class="px-3 py-1 bg-green-600 text-white rounded text-sm disabled:opacity-50 hover:bg-green-700"
209	            disabled={joining || !joinUsername.trim()}
210	            onclick={joinGame}
211	          >
212	            {joining ? $_('game_room.joining') : $_('game_room.join')}
213	          </button>
214	        </div>
215	      {/if}
216	
217	      {#if isOwner}
218	        <div class="pt-1">
219	          <button
220	            class="px-3 py-1 bg-red-600 text-white rounded text-sm disabled:opacity-50 hover:bg-red-700"
221	            disabled={cancelling}
222	            onclick={cancelGame}
223	          >
224	            {cancelling ? $_('game_room.cancelling') : $_('game_room.cancel_game')}
225	          </button>
226	        </div>
227	      {/if}
228	    </div>
229	  {/if}
230	
231	  <!-- Finished banner -->
232	  {#if session.status === "finished"}
233	    <div class="p-4 mb-4 rounded-lg text-sm space-y-3
234	                bg-green-50 border border-green-200
235	                dark:bg-green-900/20 dark:border-green-700">
236	      <p class="font-medium">
237	        {#if session.winner}
238	          {session.winner === myUsername ? $_('game_room.you_win') : $_('game_room.winner_wins', { values: { winner: session.winner } })}
239	        {:else}
240	          {$_('game_room.draw')}
241	        {/if}
242	      </p>
243	
244	      {#if session.rematch_session_id}
245	        <!-- Rematch already created — both players can jump in -->
246	        <button
247	          class="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700 text-sm"
248	          onclick={goToRematch}
249	        >
250	          {$_('game_room.go_to_rematch')}
251	        </button>
252	      {:else if isParticipant}
253	        <!-- Either participant can trigger the rematch -->
254	        <button
255	          class="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700 text-sm disabled:opacity-50"
256	          disabled={rematching}
257	          onclick={requestRematch}
258	        >
259	          {rematching ? $_('game_room.starting_rematch') : $_('game_room.play_again')}
260	        </button>
261	      {/if}
262	    </div>
263	  {/if}
264	
265	  <!-- Turn indicator -->
266	  {#if session.status === "playing" && !('phase' in (session.state ?? {}))}
267	    <p class="text-sm text-gray-600 dark:text-gray-400 mb-4">
268	      {#if session.current_turn === myUsername}
269	        <span class="font-semibold text-indigo-700 dark:text-indigo-400">{$_('game_room.your_turn')}</span>
270	      {:else}
271	        {$_('game_room.their_turn', { values: { player: session.current_turn } })}
272	      {/if}
273	    </p>
274	  {/if}
275	
276	  <!-- How to play -->
277	  <details class="mb-4 group">
278	    <summary class="cursor-pointer text-sm text-indigo-600 dark:text-indigo-400 hover:underline list-none flex items-center gap-1">
279	      <span class="text-xs">▶</span>
280	      <span class="group-open:hidden">{$_('game_room.how_to_play')}</span>
281	      <span class="hidden group-open:inline">{$_('game_room.how_to_play')}</span>
282	    </summary>
283	    <ul class="mt-2 text-sm text-gray-600 dark:text-gray-400 space-y-1 list-disc list-inside">
284	      {#each $_(`games.${session.game_slug}.how_to_play`).split('\n') as rule}
285	        <li>{rule}</li>
286	      {/each}
287	    </ul>
288	  </details>
289	
290	  <!-- Game board -->
291	  {#if GameComponent}
292	    <GameComponent {session} {myUsername} onAction={sendAction} />
293	  {:else}
294	    <p class="text-gray-500 dark:text-gray-400 text-sm">{$_('game_room.no_ui', { values: { slug: session.game_slug } })}</p>
295	  {/if}
296	{/if}
