1	<script>
2	  import { onMount, onDestroy } from "svelte";
3	  import { _ } from 'svelte-i18n';
4	  import { api } from "../lib/api.js";
5	  import { getSavedUsername, saveUsername } from "../lib/username.js";
6	  import GameCard from "../components/GameCard.svelte";
7	
8	  let { onJoinGame, onHistory } = $props();
9	
10	  let sessions = $state([]);
11	  let games = $state([]);
12	  let stats = $state(null);
13	  let publicSessions = $state([]);
14	  let loading = $state(true);
15	  let error = $state(null);
16	
17	  let showNewGame = $state(false);
18	  let selectedSlug = $state("");
19	  let username = $state(getSavedUsername());
20	  let isPublic = $state(false);
21	  let creating = $state(false);
22	
23	  let activeSessions = $derived(sessions.filter((s) => s.status !== "finished"));
24	  let hasFinished = $derived(sessions.some((s) => s.status === "finished"));
25	
26	  // Public sessions where the viewer is not already a participant
27	  let joinableSessions = $derived(publicSessions.filter((s) => s.my_username === null));
28	
29	  async function refreshPublic() {
30	    if (document.hidden) return;
31	    try {
32	      [publicSessions, stats] = await Promise.all([api.publicSessions(), api.stats()]);
33	    } catch {}
34	  }
35	
36	  let pollTimer;
37	
38	  onMount(async () => {
39	    try {
40	      [sessions, games, stats, publicSessions] = await Promise.all([
41	        api.mySessions(),
42	        api.games(),
43	        api.stats(),
44	        api.publicSessions(),
45	      ]);
46	      if (sessions.every((s) => s.status === "finished")) {
47	        showNewGame = true;
48	      }
49	    } catch (e) {
50	      error = e.message;
51	    } finally {
52	      loading = false;
53	    }
54	
55	    pollTimer = setInterval(refreshPublic, 5000);
56	    document.addEventListener("visibilitychange", refreshPublic);
57	  });
58	
59	  onDestroy(() => {
60	    clearInterval(pollTimer);
61	    document.removeEventListener("visibilitychange", refreshPublic);
62	  });
63	
64	  async function createGame() {
65	    if (!selectedSlug || !username.trim()) return;
66	    creating = true;
67	    try {
68	      const trimmed = username.trim();
69	      saveUsername(trimmed);
70	      const session = await api.createSession(selectedSlug, trimmed, isPublic);
71	      onJoinGame(session.uuid);
72	    } catch (e) {
73	      error = e.message;
74	    } finally {
75	      creating = false;
76	    }
77	  }
78	</script>
79	
80	<!-- Platform stats banner -->
81	{#if stats}
82	  <div class="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400 mb-8 mt-1">
83	    <span class="inline-flex items-center gap-1.5">
84	      <span class="relative flex h-2 w-2">
85	        {#if stats.active_games > 0}
86	          <span class="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
87	        {/if}
88	        <span class="relative inline-flex rounded-full h-2 w-2 {stats.active_games > 0 ? 'bg-green-500' : 'bg-gray-300 dark:bg-gray-600'}"></span>
89	      </span>
90	      {$_('lobby.stats_in_progress', { values: { count: stats.active_games } })}
91	    </span>
92	    <span class="text-gray-300 dark:text-gray-600">·</span>
93	    <span>{$_('lobby.stats_total', { values: { count: stats.total_games } })}</span>
94	  </div>
95	{/if}
96	
97	<h1 class="text-2xl font-bold mb-6">{$_('lobby.title')}</h1>
98	
99	{#if error}
100	  <p class="text-red-500 mb-4">{error}</p>
101	{/if}
102	
103	{#if loading}
104	  <p class="text-gray-500 dark:text-gray-400">{$_('lobby.loading')}</p>
105	{:else}
106	  {#if activeSessions.length === 0}
107	    <p class="text-gray-500 dark:text-gray-400 mb-6">{$_('lobby.no_active')}</p>
108	  {:else}
109	    <div class="space-y-3 mb-8">
110	      {#each activeSessions as session (session.uuid)}
111	        <GameCard {session} onClick={() => onJoinGame(session.uuid)} />
112	      {/each}
113	    </div>
114	  {/if}
115	
116	  {#if !showNewGame}
117	    <button
118	      class="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700"
119	      onclick={() => { showNewGame = true; }}
120	    >
121	      {$_('lobby.new_game')}
122	    </button>
123	  {/if}
124	
125	  {#if showNewGame}
126	    <div class="mt-4 p-4 border rounded-lg space-y-3
127	                bg-gray-50 border-gray-200
128	                dark:bg-gray-800 dark:border-gray-700">
129	      <div class="flex items-center justify-between">
130	        <h2 class="font-semibold">{$_('lobby.create.title')}</h2>
131	        <button
132	          class="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 text-xl leading-none"
133	          onclick={() => { showNewGame = false; }}
134	        >×</button>
135	      </div>
136	
137	      <div>
138	        <label for="new-game-username" class="block text-sm text-gray-600 dark:text-gray-400 mb-1">
139	          {$_('lobby.create.username_label')}
140	        </label>
141	        <input
142	          id="new-game-username"
143	          class="w-full border rounded px-3 py-2
144	                 border-gray-300 bg-white text-gray-900 placeholder-gray-400
145	                 dark:border-gray-600 dark:bg-gray-700 dark:text-gray-100 dark:placeholder-gray-500"
146	          placeholder={$_('lobby.create.username_placeholder')}
147	          bind:value={username}
148	        />
149	      </div>
