3	async function request(path, options = {}) {
4	  const res = await fetch(path, {
5	    ...options,
6	    headers: {
7	      "Content-Type": "application/json",
8	      "X-Player-Token": getToken(),
9	      ...options.headers,
10	    },
11	  });
12	  if (!res.ok) {
13	    const err = await res.json().catch(() => ({ detail: res.statusText }));
14	    throw new Error(err.detail ?? "Request failed");
15	  }
16	  if (res.status === 204) return null;
17	  return res.json();
18	}
