3	export function createGameSocket(sessionId, { onState, onError, onCancelled }) {
4	  const protocol = location.protocol === "https:" ? "wss" : "ws";
5	  const url = `${protocol}://${location.host}/ws/${sessionId}?token=${encodeURIComponent(getToken())}`;
6	  let ws;
7	  let dead = false;
8	
9	  function connect() {
10	    ws = new WebSocket(url);
11	
12	    ws.onopen = () => {};
13	
14	    ws.onmessage = (event) => {
15	      const msg = JSON.parse(event.data);
16	      if (msg.type === "state") onState(msg.session);
17	      if (msg.type === "error") onError?.(msg.message);
18	      if (msg.type === "cancelled") onCancelled?.();
19	    };
20	
21	    ws.onclose = () => {
22	      if (!dead) setTimeout(connect, 2000); // auto-reconnect
23	    };
24	
25	    ws.onerror = () => ws.close();
26	  }
27	
28	  connect();
29	
30	  return {
31	    sendAction(action) {
32	      ws.send(JSON.stringify({ type: "action", action }));
33	    },
34	    close() {
35	      dead = true;
36	      ws.close();
37	    },
38	  };
39	}
