1	const TOKEN_KEY = "ludus_player_token";
2	
3	function generateToken() {
4	  return crypto.randomUUID();
5	}
6	
7	export function getToken() {
8	  let token = localStorage.getItem(TOKEN_KEY);
9	  if (!token) {
10	    token = generateToken();
11	    localStorage.setItem(TOKEN_KEY, token);
12	  }
13	  return token;
14	}
15	
16	export function importToken(token) {
17	  localStorage.setItem(TOKEN_KEY, token);
18	  // Reload so all reactive state re-initialises with the new token
19	  window.location.reload();
20	}
21	
22	export function exportToken() {
23	  return localStorage.getItem(TOKEN_KEY) ?? getToken();
24	}
25	
26	/**
27	 * Build a URL the user can share to import their token on another device.
28	 * Scanning the QR of this URL opens the site and triggers auto-import.
29	 */
30	export function buildImportUrl(token) {
31	  const url = new URL(window.location.href);
32	  url.pathname = "/";
33	  url.search = "";
34	  url.hash = "";
35	  url.searchParams.set("import_token", token);
36	  return url.toString();
37	}
38	
39	/**
40	 * Call on app startup. If `?import_token=...` is in the URL, prompt the user
41	 * to confirm before overwriting their local token.
42	 * Returns the token to use for this session.
43	 */
44	export function handleImportFromUrl() {
45	  const params = new URLSearchParams(window.location.search);
46	  const incoming = params.get("import_token");
47	  if (!incoming) return null;
48	
49	  // Strip the param from the URL without reloading
50	  params.delete("import_token");
51	  const clean =
52	    window.location.pathname + (params.toString() ? "?" + params : "");
53	  window.history.replaceState({}, "", clean);
54	
55	  return incoming; // caller shows confirmation dialog
56	}
