3	const SW_PATH = "/sw.js";
4	
5	function urlBase64ToUint8Array(base64String) {
6	  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
7	  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
8	  const raw = atob(base64);
9	  return Uint8Array.from([...raw].map((c) => c.charCodeAt(0)));
10	}
11	
12	async function getVapidKey() {
13	  const res = await fetch("/api/push/vapid-public-key");
14	  if (!res.ok) return null;
15	  const { publicKey } = await res.json();
16	  return publicKey;
17	}
18	
19	async function sendSubscriptionToServer(subscription, method = "POST") {
20	  await fetch("/api/push/subscribe", {
21	    method,
22	    headers: {
23	      "Content-Type": "application/json",
24	      "X-Player-Token": getToken(),
25	    },
26	    body: JSON.stringify({ subscription: subscription.toJSON() }),
27	  });
28	}
29	
30	/**
31	 * Register the service worker and subscribe to push notifications.
32	 * Safe to call multiple times — returns early if already subscribed.
33	 * Returns the permission state: 'granted' | 'denied' | 'default' | 'unsupported'
34	 */
35	export async function subscribeToPush() {
36	  if (!("serviceWorker" in navigator) || !("PushManager" in window)) {
37	    return "unsupported";
38	  }
39	
40	  const vapidKey = await getVapidKey();
41	  if (!vapidKey) return "unsupported"; // push not configured on server
42	
43	  const reg = await navigator.serviceWorker.register(SW_PATH);
44	  await navigator.serviceWorker.ready;
45	
46	  const existing = await reg.pushManager.getSubscription();
47	  if (existing) {
48	    // already subscribed — ensure server has it (idempotent)
49	    await sendSubscriptionToServer(existing);
50	    return "granted";
51	  }
52	
53	  const permission = await Notification.requestPermission();
54	  if (permission !== "granted") return permission;
55	
56	  const subscription = await reg.pushManager.subscribe({
57	    userVisibleOnly: true,
58	    applicationServerKey: urlBase64ToUint8Array(vapidKey),
59	  });
60	
61	  await sendSubscriptionToServer(subscription);
62	  return "granted";
63	}
64	
65	export async function unsubscribeFromPush() {
66	  if (!("serviceWorker" in navigator)) return;
67	  const reg = await navigator.serviceWorker.getRegistration(SW_PATH);
68	  if (!reg) return;
69	  const subscription = await reg.pushManager.getSubscription();
70	  if (!subscription) return;
71	  await sendSubscriptionToServer(subscription, "DELETE");
72	  await subscription.unsubscribe();
73	}
74	
75	export function isPushSupported() {
76	  return "serviceWorker" in navigator && "PushManager" in window;
77	}
