4	  let payload;
5	  try {
6	    payload = event.data.json();
7	  } catch {
8	    payload = { title: "Ludus", body: event.data.text(), url: "/" };
9	  }
10	
11	  event.waitUntil(
12	    self.registration.showNotification(payload.title ?? "Ludus", {
13	      body: payload.body,
