23	self.addEventListener("notificationclick", (event) => {
24	  event.notification.close();
25	  const url = event.notification.data?.url ?? "/";
26	  event.waitUntil(
27	    clients
28	      .matchAll({ type: "window", includeUncontrolled: true })
29	      .then((windowClients) => {
30	        // Focus existing tab if already open
31	        for (const client of windowClients) {
32	          if (client.url.endsWith(url) && "focus" in client) {
33	            return client.focus();
34	          }
35	        }
36	        return clients.openWindow(url);
37	      })
38	  );
